    "                    hm[wi] |= ((ulong)0x80UL) << (bi * 8);\n"
    "                }\n"
    "                sha512_block(&istate[0], hm);\n"
    "                int rem = mlen - 128;\n"
    "                for (int i = 0; i < 16; i++) hm[i] = 0UL;\n"
    "                if (rem > 0) {\n"
    "                    for (int i = 0; i < rem; i++) {\n"
    "                        ulong v = (ulong)salt_buf[128 + i];\n"
    "                        hm[i >> 3] |= v << ((7 - (i & 7)) * 8);\n"
    "                    }\n"
    "                }\n"
    "                if (mlen >= 128) {\n"
    "                    int p = (rem > 0) ? rem : 0;\n"
    "                    int wi = p >> 3;\n"
    "                    int bi = 7 - (p & 7);\n"
    "                    hm[wi] |= ((ulong)0x80UL) << (bi * 8);\n"
    "                }\n"
    "                hm[15] = (ulong)(128 + mlen) * 8UL;\n"
    "                sha512_block(&istate[0], hm);\n"
    "            }\n"
    "        }\n"
    "\n"
    "        /* Step 3: outer = SHA512((key ^ opad) || inner_hash). istate[8]\n"
    "         * is BE; all 8 words copied directly into M[0..7] (no truncation,\n"
    "         * vs SHA-384's 6-word truncation). M[8] = 0x8000000000000000UL\n"
    "         * (0x80 BE at byte 64 = high octet of word 8); M[15] = (128 + 64)\n"
    "         * * 8 = 1536. Slab oracle line 111-127 / 225-238. */\n"
    "        ulong opad_block[16];\n"
    "        for (int i = 0; i < 16; i++)\n"
    "            opad_block[i] = key_block[i] ^ 0x5c5c5c5c5c5c5c5cUL;\n"
    "        for (int i = 0; i < 16; i++)\n"
    "            hm[i] = bswap64(opad_block[i]);\n"
    "\n"
    "        ulong ostate[8] = {\n"
    "            0x6a09e667f3bcc908UL, 0xbb67ae8584caa73bUL,\n"
    "            0x3c6ef372fe94f82bUL, 0xa54ff53a5f1d36f1UL,\n"
    "            0x510e527fade682d1UL, 0x9b05688c2b3e6c1fUL,\n"
    "            0x1f83d9abfb41bd6bUL, 0x5be0cd19137e2179UL };\n"
    "        sha512_block(&ostate[0], hm);\n"
    "\n"
    "        for (int i = 0; i < 8; i++) hm[i] = istate[i];\n"
    "        hm[8] = 0x8000000000000000UL;   /* 0x80 BE at byte 64 */\n"
    "        for (int i = 9; i < 15; i++) hm[i] = 0UL;\n"
    "        hm[14] = 0UL;\n"
    "        hm[15] = (ulong)(128 + 64) * 8UL;   /* 1536 bits */\n"
    "        sha512_block(&ostate[0], hm);\n"
    "\n"
    "        /* Write final BE state into st->state[0..7]; template_state_to_h\n"
    "         * decomposes into st->h[0..15] (16 LE uint32 words = 64 bytes).\n"
    "         * No truncation (vs SHA-384's 6-word state). */\n"
    "        for (int i = 0; i < 8; i++) st->state[i] = ostate[i];\n"
    "        template_state_to_h(st);\n"
    "        return;\n"
    "    }\n"
    "\n"
    "    /* Family E carrier-only suppression: when this fragment is generated\n"
    "     * for the SHA-384 spec (HASH_WORDS=12), modes < 5 fall through to the\n"
    "     * SHA384(salt||pass) main body below. No JOB_SHA384SALTPASS algorithm\n"
    "     * exists in mdxfind; the host never sets algo_mode<5 for this kernel\n"
    "     * in production. The body below executes correctly should a future\n"
    "     * SHA384SALTPASS algorithm be added. Family F (HASH_WORDS=16): modes\n"
    "     * < 5 fall through to the production SHA512(salt||pass) main body\n"
    "     * (JOB_SHA512SALTPASS, algo_mode=0). */\n"
    "    (void)algo_mode;  /* Family E/F: actively used above; no-op for modes 0..4 */\n"
    "    ulong M[16];\n"
    "    int total_len = (int)slen + len;\n"
    "    int pos = 0;\n"
    "\n"
    "    /* Process complete 128-byte blocks. Build M[] BIG-ENDIAN directly\n"
    "     * from bytes; salt bytes for p < slen, password bytes for p >= slen.\n"
    "     * Per-byte BE position: byte i into word (i >> 3) at shift\n"
    "     * (7 - (i & 7)) * 8. */\n"
    "    while (total_len - pos >= HASH_BLOCK_BYTES) {\n"
    "        for (int j = 0; j < 16; j++) M[j] = 0UL;\n"
    "        for (int i = 0; i < HASH_BLOCK_BYTES; i++) {\n"
    "            int p = pos + i;\n"
    "            uchar c;\n"
    "            if (p < (int)slen) {\n"
    "                c = salt_buf[p];\n"
    "            } else {\n"
    "                c = data[p - (int)slen];\n"
    "            }\n"
    "            M[i >> 3] |= ((ulong)c) << ((7 - (i & 7)) * 8);\n"
    "        }\n"
    "        sha512_block(&st->state[0], M);\n"
    "        pos += HASH_BLOCK_BYTES;\n"
    "    }\n"
    "\n"
    "    /* Build final block(s): tail bytes + 0x80 marker + zeros + 128-bit\n"
    "     * BE length. */\n"
    "    int rem = total_len - pos;  /* 0..127 */\n"
    "    for (int j = 0; j < 16; j++) M[j] = 0UL;\n"
    "    for (int i = 0; i < rem; i++) {\n"
    "        int p = pos + i;\n"
    "        uchar c;\n"
    "        if (p < (int)slen) {\n"
    "            c = salt_buf[p];\n"
    "        } else {\n"
    "            c = data[p - (int)slen];\n"
    "        }\n"
    "        M[i >> 3] |= ((ulong)c) << ((7 - (i & 7)) * 8);\n"
    "    }\n"
    "    /* 0x80 padding marker, BE byte position. */\n"
    "    {\n"
    "        int wi = rem >> 3;\n"
    "        int bi = 7 - (rem & 7);\n"
    "        M[wi] |= ((ulong)0x80UL) << (bi * 8);\n"
    "    }\n"
    "\n"
    "    if (rem < 112) {\n"
    "        /* Length fits in this block. M[14] = high 64 bits of bit count\n"
    "         * (= 0 for total_len < 2^57 bytes), M[15] = low 64 bits. */\n"
    "        M[14] = 0UL;\n"
    "        M[15] = (ulong)((ulong)total_len * 8UL);\n"
    "        sha512_block(&st->state[0], M);\n"
    "    } else {\n"
    "        /* Need one extra padding-only block to hold the length. */\n"
    "        sha512_block(&st->state[0], M);\n"
    "        for (int j = 0; j < 16; j++) M[j] = 0UL;\n"
    "        M[14] = 0UL;\n"
    "        M[15] = (ulong)((ulong)total_len * 8UL);\n"
    "        sha512_block(&st->state[0], M);\n"
    "    }\n"
    "\n"
    "    /* Decompose final state into h[16] LE uint32 for digest emit. */\n"
    "    template_state_to_h(st);\n"
    "}\n"
    "\n"
    "/* template_iterate: -i loop step. Re-encode the digest as 128-byte\n"
    " * lowercase hex ASCII and rehash. SHA-512's hex output is 128 chars,\n"
    " * which exactly fills one HASH_BLOCK_BYTES (128) block — but the\n"
    " * 0x80 marker + 16-byte length need a SECOND block.\n"
    " *\n"
    " * Mirrors gpu_sha512_core.cl rev 1.x lines 250-276 byte-for-byte:\n"
    " *   - sha512_to_hex_lc(state, M) : 8 ulong BE state -> 16 ulong BE\n"
    " *     hex M[] (each ulong holds 8 hex chars BE)\n"
    " *   - state reset to SHA-512 IV; sha512_block(state, M)\n"
    " *   - second block: M[0] = 0x8000000000000000UL BE (0x80 at byte 128),\n"
    " *     M[1..14] = 0, M[15] = 128*8 = 1024\n"
    " *   - sha512_block(state, M) again\n"
    " *   - decompose state -> h[16].\n"
    " *\n"
    " * No salt re-application: matches CPU iter convention at\n"
    " * mdxfind.c JOB_SHA512SALTPASS line 14016 (prmd5(curin.h, newbuf, 128) ;\n"
    " * mysha512(newbuf, 128, curin.h)). */\n"
    "static inline void template_iterate(template_state *st)\n"
    "{\n"
    "    ulong M[16];\n"
    "    /* sha512_to_hex_lc (gpu_common.cl line ~922) writes 16 ulong BE\n"
    "     * hex words into M[] from state[]. */\n"
    "    sha512_to_hex_lc(&st->state[0], M);\n"
    "    /* Reset state to SHA-512 IV; absorb the prepared hex block. */\n"
    "    st->state[0] = 0x6a09e667f3bcc908UL;\n"
    "    st->state[1] = 0xbb67ae8584caa73bUL;\n"
    "    st->state[2] = 0x3c6ef372fe94f82bUL;\n"
    "    st->state[3] = 0xa54ff53a5f1d36f1UL;\n"
    "    st->state[4] = 0x510e527fade682d1UL;\n"
    "    st->state[5] = 0x9b05688c2b3e6c1fUL;\n"
    "    st->state[6] = 0x1f83d9abfb41bd6bUL;\n"
    "    st->state[7] = 0x5be0cd19137e2179UL;\n"
    "    sha512_block(&st->state[0], M);\n"
    "\n"
    "    /* Second block: pad + length only. */\n"
    "    M[0] = 0x8000000000000000UL;     /* 0x80 BE at byte position 128 */\n"
    "    for (int j = 1; j < 15; j++) M[j] = 0UL;\n"
    "    M[14] = 0UL;\n"
    "    M[15] = 128UL * 8UL;             /* 128 hex chars = 1024 bits */\n"
    "    sha512_block(&st->state[0], M);\n"
    "\n"
    "    /* Decompose updated state into h[16]. */\n"
    "    template_state_to_h(st);\n"
    "}\n"
    "\n"
    "/* template_digest_compare: probe the compact table with the leading\n"
    " * 16 bytes of the final digest. h[0..3] already holds the 4 LE uint32\n"
    " * leading words (populated by template_state_to_h via finalize/iterate).\n"
    " *\n"
    " * Mirrors gpu_sha512_packed.cl line 75-80 exactly: probe_compact[_idx]\n"
    " * called with h[0], h[1], h[2], h[3]. */\n"
    "static inline int template_digest_compare(\n"
    "    const template_state *st,\n"
    "    __global const uint *compact_fp, __global const uint *compact_idx,\n"
    "    ulong compact_mask, uint max_probe, uint hash_data_count,\n"
    "    __global const uchar *hash_data_buf, __global const ulong *hash_data_off,\n"
    "    __global const ulong *overflow_keys, __global const uchar *overflow_hashes,\n"
    "    __global const uint *overflow_offsets, uint overflow_count,\n"
    "    uint *out_idx)\n"
    "{\n"
    "    return probe_compact_idx(\n"
    "        st->h[0], st->h[1], st->h[2], st->h[3],\n"
    "        compact_fp, compact_idx,\n"
    "        compact_mask, max_probe, hash_data_count,\n"
    "        hash_data_buf, hash_data_off,\n"
    "        overflow_keys, overflow_hashes, overflow_offsets, overflow_count,\n"
    "        out_idx);\n"
    "}\n"
    "\n"
    "/* template_emit_hit: emit a hit. Wraps EMIT_HIT_16 (SHA-512 = 16 uint32\n"
    " * digest words, populated LE-byteswapped in st->h by finalize/iterate).\n"
    " * Wire format matches gpu_sha512_packed.cl emit. */\n"
    "#define template_emit_hit(hits, hit_count, max_hits, st, widx, sidx, iter) \\\n"
    "    EMIT_HIT_16((hits), (hit_count), (max_hits), \\\n"
    "                (widx), (sidx), (iter), ((st)->h))\n"
    "\n"
    "/* B3 dedup+overflow-aware variant. See gpu_sha512_core.cl for protocol\n"
    " * notes. */\n"
    "#define template_emit_hit_or_overflow(hits, hit_count, max_hits, st, widx, sidx, iter, \\\n"
    "                                      hashes_shown, matched_idx, dedup_mask, \\\n"
    "                                      ovr_set, ovr_gid, lane_gid) \\\n"
    "    EMIT_HIT_16_DEDUP_OR_OVERFLOW((hits), (hit_count), (max_hits), \\\n"
    "               (widx), (sidx), (iter), ((st)->h), \\\n"
    "               (hashes_shown), (matched_idx), (dedup_mask), \\\n"
    "               (ovr_set), (ovr_gid), (lane_gid))\n"
;
